  clientSelected(event: SearchResult) {
    this.SearchResult = event;
    console.log(event);

    let client_key = this.SearchResult.client_key.toString();
    let application_key = this.SearchResult.application_key.toString();
    let org_code = this.org_code_user_info.toString();
    let branch_code = this.branch_code_user_info.toString();

    this.http
      .post<LoanAppToRevisionInfo>(
        this.env.API_URL + "api/LoanApplications/ClientLoanApplicationRevision",
        {
          client_key,
          application_key,
          org_code,
          branch_code,
        }
      )
      .subscribe({
        next: (data) => {
          this.LoanAppToRevisionInfo = data;
          console.log("data here:", this.LoanAppToRevisionInfo);
          this.getLoanAppToRevision();
        },
        error: (err) => {},
      });
  }

